-- ============================================================
-- 전기기사 필기 기출문제 데이터 마이그레이션
-- 15개 시험 (2018~2022, 2025-3), 총 1500문제
-- Neon DB (PostgreSQL) 에서 실행
-- ============================================================

BEGIN;

INSERT INTO exam_categories (name, description, sort_order, is_active, created_at, updated_at)
VALUES ('전기기사', '전기기사 필기 기출문제', 30, true, NOW(), NOW())
ON CONFLICT (name) DO NOTHING;

-- === 전기기사 2018년 1회 ===
INSERT INTO exams (category_id, name, year, round, exam_mode, duration_minutes, is_published, sort_order, min_tier, created_at, updated_at)
SELECT ec.id, '전기기사 2018년 1회', 2018, 1, 'PRACTICE', 150, true, 20181, 'GUEST', NOW(), NOW()
FROM exam_categories ec WHERE ec.name = '전기기사'
ON CONFLICT (category_id, year, round) DO NOTHING;
INSERT INTO subjects (exam_id, name, questions_per_attempt, order_no)
SELECT e.id, '전기자기학', 20, 1
FROM exams e JOIN exam_categories ec ON e.category_id = ec.id
WHERE ec.name = '전기기사' AND e.year = 2018 AND e.round = 1
AND NOT EXISTS (SELECT 1 FROM subjects s WHERE s.exam_id = e.id AND s.name = '전기자기학');
INSERT INTO subjects (exam_id, name, questions_per_attempt, order_no)
SELECT e.id, '전력공학', 20, 2
FROM exams e JOIN exam_categories ec ON e.category_id = ec.id
WHERE ec.name = '전기기사' AND e.year = 2018 AND e.round = 1
AND NOT EXISTS (SELECT 1 FROM subjects s WHERE s.exam_id = e.id AND s.name = '전력공학');
INSERT INTO subjects (exam_id, name, questions_per_attempt, order_no)
SELECT e.id, '전기기기', 20, 3
FROM exams e JOIN exam_categories ec ON e.category_id = ec.id
WHERE ec.name = '전기기사' AND e.year = 2018 AND e.round = 1
AND NOT EXISTS (SELECT 1 FROM subjects s WHERE s.exam_id = e.id AND s.name = '전기기기');
INSERT INTO subjects (exam_id, name, questions_per_attempt, order_no)
SELECT e.id, '회로이론 및 제어공학', 20, 4
FROM exams e JOIN exam_categories ec ON e.category_id = ec.id
WHERE ec.name = '전기기사' AND e.year = 2018 AND e.round = 1
AND NOT EXISTS (SELECT 1 FROM subjects s WHERE s.exam_id = e.id AND s.name = '회로이론 및 제어공학');
INSERT INTO subjects (exam_id, name, questions_per_attempt, order_no)
SELECT e.id, '전기설비기술기준', 20, 5
FROM exams e JOIN exam_categories ec ON e.category_id = ec.id
WHERE ec.name = '전기기사' AND e.year = 2018 AND e.round = 1
AND NOT EXISTS (SELECT 1 FROM subjects s WHERE s.exam_id = e.id AND s.name = '전기설비기술기준');
INSERT INTO questions (question_code, exam_id, subject_id, question_type, question_text, choice_1, choice_2, choice_3, choice_4, choice_1_image, choice_2_image, choice_3_image, choice_4_image, answer, image_url, is_active, created_at, updated_at)
SELECT 'ELEC-E-EM-001', e.id, s.id, 'MULTIPLE_CHOICE',
  '',
  '', '', '', '',
  'https://image.engineerlab.co.kr/ibt/ee_pil/ee_pil_prev/18_01/images/EE18_01_001_1.png', 'https://image.engineerlab.co.kr/ibt/ee_pil/ee_pil_prev/18_01/images/EE18_01_001_2.png', 'https://image.engineerlab.co.kr/ibt/ee_pil/ee_pil_prev/18_01/images/EE18_01_001_3.png', 'https://image.engineerlab.co.kr/ibt/ee_pil/ee_pil_prev/18_01/images/EE18_01_001_4.png',
  3, 'https://image.engineerlab.co.kr/ibt/ee_pil/ee_pil_prev/18_01/images/EE18_01_001.png', true, NOW(), NOW()
FROM exams e
JOIN exam_categories ec ON e.category_id = ec.id
JOIN subjects s ON s.exam_id = e.id AND s.name = '전기자기학'
WHERE ec.name = '전기기사' AND e.year = 2018 AND e.round = 1
ON CONFLICT (question_code) DO NOTHING;
