-- === 전기기사 2018년 2회 ===
INSERT INTO exams (category_id, name, year, round, exam_mode, duration_minutes, is_published, sort_order, min_tier, created_at, updated_at)
SELECT ec.id, '전기기사 2018년 2회', 2018, 2, 'PRACTICE', 150, true, 20182, 'GUEST', NOW(), NOW()
FROM exam_categories ec WHERE ec.name = '전기기사'
ON CONFLICT (category_id, year, round) DO NOTHING;
INSERT INTO subjects (exam_id, name, questions_per_attempt, order_no)
SELECT e.id, '전기자기학', 20, 1
FROM exams e JOIN exam_categories ec ON e.category_id = ec.id
WHERE ec.name = '전기기사' AND e.year = 2018 AND e.round = 2
AND NOT EXISTS (SELECT 1 FROM subjects s WHERE s.exam_id = e.id AND s.name = '전기자기학');
INSERT INTO subjects (exam_id, name, questions_per_attempt, order_no)
SELECT e.id, '전력공학', 20, 2
FROM exams e JOIN exam_categories ec ON e.category_id = ec.id
WHERE ec.name = '전기기사' AND e.year = 2018 AND e.round = 2
AND NOT EXISTS (SELECT 1 FROM subjects s WHERE s.exam_id = e.id AND s.name = '전력공학');
INSERT INTO subjects (exam_id, name, questions_per_attempt, order_no)
SELECT e.id, '전기기기', 20, 3
FROM exams e JOIN exam_categories ec ON e.category_id = ec.id
WHERE ec.name = '전기기사' AND e.year = 2018 AND e.round = 2
AND NOT EXISTS (SELECT 1 FROM subjects s WHERE s.exam_id = e.id AND s.name = '전기기기');
