  4, 'https://image.engineerlab.co.kr/ibt/ee_pil/ee_pil_prev/25_03/images/EE25_03_100.png', true, NOW(), NOW()
FROM exams e
JOIN exam_categories ec ON e.category_id = ec.id
JOIN subjects s ON s.exam_id = e.id AND s.name = '전기설비기술기준'
WHERE ec.name = '전기기사' AND e.year = 2025 AND e.round = 3
ON CONFLICT (question_code) DO NOTHING;

COMMIT;